/**
 * Utility Input Normalizers
 * 
 * Functions to normalize user input for utility forms.
 */

/**
 * Normalizes meter input (allows letter prefix + digits)
 */
export const normalizeMeterInput = (value) => {
  if (value === '') {return '';}

  const upper = value.toUpperCase();
  if (/^[A-Z]?\d*$/.test(upper)) {
    return upper;
  }

  const cleaned = upper.replace(/[^A-Z0-9]/g, '');
  const match = cleaned.match(/^([A-Z]?)(\d*)/);
  return `${match?.[1] || ''}${match?.[2] || ''}`;
};

/**
 * Normalizes TV card input based on provider
 */
export const normalizeTvCardInput = (value, provider) => {
  // Digits only; enforce max length based on provider
  const digits = (value || '').replace(/\D/g, '');

  let maxLen = 11;
  if (provider === 'DStv') {
    maxLen = 11; // 10-11 digits allowed, we cap at 11
  } else if (provider === 'GOtv') {
    maxLen = 10;
  } else if (provider === 'StarTimes') {
    maxLen = 11;
  }

  return digits.slice(0, maxLen);
};

