/**
 * Airtime Form Component
 * 
 * Form for purchasing airtime for MTN, Telecel, and AirtelTigo networks.
 * This component demonstrates the pattern for all utility form components.
 */

import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { payAirtime } from '@/features/utilities/services/utilityService.js';
import { isValidGhanaPhone } from '@/features/utilities/utils/validators.js';
import { NETWORKS } from '@/features/utilities/constants';
import { useMutation } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import { getFriendlyErrorMessage } from '@/features/utilities/utils/errors.js';
import { countries } from '@/shared/utils/constants/countries-with-flags.js';
import { FlagIcon } from '@/shared/components';
import CustomSelect from '@/shared/components/CustomSelect.jsx';

const AirtimeForm = ({ onPaymentSuccess }) => {
  const { t } = useTranslation();
  const { success, error: showError } = useToast();

  const [selectedNetwork, setSelectedNetwork] = useState('');
  const [phoneNumber, setPhoneNumber] = useState('');
  const [countryCode, setCountryCode] = useState('+233');
  const [amount, setAmount] = useState('');

  // Use React Query mutation for airtime payment
  const payAirtimeMutation = useMutation({
    mutationFn: async ({ network, phone, amount }) => {
      return await payAirtime(network, phone, amount);
    },
    invalidateQueries: [
      queryKeys.utilities.all(),
      queryKeys.dashboard.all(),
      queryKeys.wallet.balance(),
      queryKeys.reports.all(),
    ],
    onSuccess: () => {
      success(
        t('paymentProcessedSuccessfully', {
          ns: 'utilities',
          amount: parseFloat(amount).toLocaleString(),
          provider: selectedNetwork
        })
      );

      // Reset form
      setPhoneNumber('');
      setAmount('');
      setSelectedNetwork('');

      if (onPaymentSuccess) {
        onPaymentSuccess();
      }
    },
    onError: (err) => {
      const fallback = t('paymentFailed', { ns: 'utilities', defaultValue: 'Payment failed. Please try again.' });
      showError(getFriendlyErrorMessage(err, fallback));
    },
  });

  // Reset when network changes
  useEffect(() => {
    setPhoneNumber('');
    setAmount('');
  }, [selectedNetwork]);

  const handlePayment = async () => {
    // Validation
    if (!selectedNetwork) {
      showError('Please select a network');
      return;
    }

    if (!phoneNumber) {
      showError('Please enter a phone number');
      return;
    }

    if (!isValidGhanaPhone(phoneNumber)) {
      showError('Please enter a valid Ghana phone number (e.g. 0244123456)');
      return;
    }

    if (!amount || Number(amount) <= 0) {
      showError('Please enter a valid amount');
      return;
    }

    payAirtimeMutation.mutate({
      network: selectedNetwork,
      phone: phoneNumber,
      amount: amount,
    });
  };

  return (
    <div>
      {/* Network Selection */}
      <div style={{ marginBottom: '20px' }}>
        <label style={{
          display: 'block',
          marginBottom: '8px',
          color: 'var(--text-primary)',
          fontWeight: '500',
          fontSize: '14px'
        }}>
          {t('selectPreferredNetwork', { ns: 'utilities' })}
        </label>
        <CustomSelect
          name="selectedNetwork"
          value={selectedNetwork}
          onChange={(e) => setSelectedNetwork(e.target.value)}
          options={[
            {
              value: NETWORKS.MTN,
              label: (
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                  <img src="/assets/mtnlogo.png" alt="MTN" style={{ width: 24, height: 24, objectFit: 'contain' }} />
                  <span>MTN</span>
                </div>
              )
            },
            {
              value: NETWORKS.TELECEL,
              label: (
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                  <img src="/assets/telecellogo.png" alt="Telecel" style={{ width: 24, height: 24, objectFit: 'contain' }} />
                  <span>Telecel</span>
                </div>
              )
            },
            {
              value: NETWORKS.AIRTELTIGO,
              label: (
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                  <img src="/assets/airtel-tigo.png" alt="AirtelTigo" style={{ width: 24, height: 24, objectFit: 'contain' }} />
                  <span>AirtelTigo</span>
                </div>
              )
            }
          ]}
          placeholder={t('chooseNetwork', { ns: 'utilities' })}
          style={{ 
            backgroundColor: 'var(--card)', 
            borderRadius: 'var(--radius-md)',
            border: '1px solid var(--border-secondary)'
          }}
          className="w-full"
        />
      </div>

      {/* Phone Number */}
      {selectedNetwork && (
        <div style={{ marginBottom: '20px' }}>
          <label style={{
            display: 'block',
            marginBottom: '8px',
            color: 'var(--text-primary)',
            fontWeight: '500',
            fontSize: '14px'
          }}>
            {t('phoneNumber', { ns: 'utilities' })}
          </label>
          <div style={{ display: 'flex', gap: '8px', alignItems: 'center', flexWrap: 'nowrap' }}>
            <div style={{ position: 'relative', width: '120px', flexShrink: 0, minWidth: '120px' }}>
              <span
                style={{
                  position: 'absolute',
                  left: '12px',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  pointerEvents: 'none',
                  zIndex: 1,
                  display: 'flex',
                  alignItems: 'center',
                }}
              >
                <FlagIcon
                  countryCode={countries.find((c) => c.dialCode === countryCode)?.code || 'GH'}
                  size="1.1em"
                />
              </span>
              <CustomSelect
                name="countryCode"
                value={countryCode}
                onChange={(e) => setCountryCode(e.target.value)}
                options={countries.map((country) => ({
                  value: country.dialCode,
                  label: country.dialCode,
                  name: country.name,
                  countryCode: country.code,
                }))}
                searchable
                showCheckmark={false}
                style={{ width: '100%' }}
              />
            </div>
            <input
              type="tel"
              value={phoneNumber}
              onChange={(e) => setPhoneNumber(e.target.value)}
              placeholder="e.g. 0244123456"
              className="input-large w-full"
              style={{ flex: 1 }}
            />
          </div>
          {phoneNumber && !isValidGhanaPhone(phoneNumber) && (
            <p style={{ marginTop: '4px', fontSize: '12px', color: 'var(--error)' }}>
              Please enter a valid Ghana phone number (e.g. 0244123456)
            </p>
          )}
        </div>
      )}

      {/* Amount */}
      {selectedNetwork && phoneNumber && (
        <div style={{ marginBottom: '20px' }}>
          <label style={{
            display: 'block',
            marginBottom: '8px',
            color: 'var(--text-primary)',
            fontWeight: '500',
            fontSize: '14px'
          }}>
            {t('amount', { ns: 'utilities' })} (GH₵)
          </label>
          <input
            type="number"
            value={amount}
            onChange={(e) => setAmount(e.target.value)}
            placeholder={t('enterAmount', { ns: 'utilities' })}
            min="0.01"
            step="0.01"
            className="input-large w-full"
          />
        </div>
      )}

      {/* Payment Button */}
      {selectedNetwork && phoneNumber && amount && (
        <div style={{ textAlign: 'center', marginTop: '24px' }}>
          <button
            className="btn primary w-full"
            onClick={handlePayment}
            disabled={payAirtimeMutation.isPending || !isValidGhanaPhone(phoneNumber) || !amount || Number(amount) <= 0}
            style={{
              padding: '12px 16px',
              fontSize: '16px',
              fontWeight: '600',
            }}
          >
            {payAirtimeMutation.isPending
              ? t('processing', { ns: 'utilities' })
              : `${t('pay', { ns: 'utilities' })} GH₵${amount || '0'}`
            }
          </button>
        </div>
      )}
    </div>
  );
};

export default AirtimeForm;

