/**
 * Electricity Form Component
 * 
 * Form for electricity bill payment supporting both prepaid and postpaid meters.
 */

import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { useUtilityVerification } from '@/features/utilities/hooks';
import { payElectricityPrepaid } from '@/features/utilities/services/utilityService.js';
import { isValidGhanaPhone } from '@/features/utilities/utils/validators.js';
import { normalizeMeterInput } from '@/features/utilities/utils/normalizers.js';
import { CustomerDetailsDisplay } from '@/features/utilities/components';
import { METER_TYPES, UTILITY_PROVIDERS } from '@/features/utilities/constants';
import { useMutation } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import { getFriendlyErrorMessage } from '@/features/utilities/utils/errors.js';
import { countries } from '@/shared/utils/constants/countries-with-flags.js';
import { FlagIcon } from '@/shared/components';
import CustomSelect from '@/shared/components/CustomSelect.jsx';


const ElectricityForm = ({ onPaymentSuccess }) => {
  const { t } = useTranslation();
  const { success, error: showError } = useToast();
  const { verify, isVerifying, isVerified, customerDetails, reset } = useUtilityVerification();

  const [meterType] = useState(METER_TYPES.PREPAID);
  const [prepaidPhone, setPrepaidPhone] = useState('');
  const [countryCode, setCountryCode] = useState('+233');
  const [meterNumber, setMeterNumber] = useState('');
  const [amount, setAmount] = useState('');
  const [clientReference, setClientReference] = useState('');

  // Use React Query mutation for electricity payment
  const payElectricityMutation = useMutation({
    mutationFn: async ({ phone, meterNumber, amount, clientReference }) => {
      return await payElectricityPrepaid({ phone, meterNumber, amount, clientReference });
    },
    invalidateQueries: [
      queryKeys.utilities.all(),
      queryKeys.dashboard.all(),
      queryKeys.wallet.balance(),
      queryKeys.reports.all(),
    ],
    onSuccess: () => {
      success(t('paymentProcessedSuccessfully', {
        ns: 'utilities',
        amount: parseFloat(amount).toLocaleString(),
        provider: 'Electricity Company of Ghana'
      }));
      // Reset form
      setPrepaidPhone('');
      setMeterNumber('');
      setAmount('');
      setClientReference('');
      reset();
      if (onPaymentSuccess) {
        onPaymentSuccess();
      }
    },
    onError: (err) => {
      const fallback = t('paymentFailed', { ns: 'utilities', defaultValue: 'Payment failed. Please try again.' });
      showError(getFriendlyErrorMessage(err, fallback));
    },
  });

  // Reset verification when prepaid phone changes
  useEffect(() => {
    reset();
    setMeterNumber('');
    setAmount('');
    setClientReference('');
  }, [prepaidPhone]);

  const handleVerify = async () => {
    try {
      if (!prepaidPhone) {
        showError('Please enter a phone number first');
        return;
      }
      if (!isValidGhanaPhone(prepaidPhone)) {
        showError('Please enter a valid Ghana phone number (e.g. 0244123456)');
        return;
      }

      const result = await verify(UTILITY_PROVIDERS.ELECTRICITY, {
        meterType: METER_TYPES.PREPAID,
        phone: prepaidPhone,
      }, {
        onSuccess: (result) => {
          if (result.meters && result.meters.length > 0) {
            setMeterNumber(result.meters[0].value);
          }
        },
        onError: (error) => {
          showError(error.message);
        },
      });

      if (result && result.meters && result.meters.length > 0) {
        setMeterNumber(result.meters[0].value);
      }
    } catch (error) {
      showError(error.message || 'Failed to verify customer details. Please try again.');
    }
  };

  const handlePayment = async () => {
    if (!prepaidPhone || !meterNumber || !clientReference || !amount) {
      showError('Please fill all required fields');
      return;
    }
    if (!isValidGhanaPhone(prepaidPhone)) {
      showError('Please enter a valid Ghana phone number (e.g. 0244123456)');
      return;
    }
    if (!isVerified) {
      showError('Please verify customer details first');
      return;
    }

    payElectricityMutation.mutate({
      phone: prepaidPhone,
      meterNumber: meterNumber,
      amount: amount,
      clientReference: clientReference,
    });
  };

  return (
    <div>
      {/* Meter Type Selection - Prepaid Only */}
      <div style={{ marginBottom: '20px' }}>
        <label style={{
          display: 'block',
          marginBottom: '8px',
          color: 'var(--text-primary)',
          fontWeight: '500',
          fontSize: '14px'
        }}>
          {t('meterType', { ns: 'utilities', defaultValue: 'Meter Type' })}
        </label>
        <div className="utility-meter-type-display">
          {t('prepaid', { ns: 'utilities', defaultValue: 'Prepaid' })}
        </div>
      </div>

      {/* Prepaid Form */}
      <>
        {/* Phone Number */}
        <div style={{ marginBottom: '20px' }}>
          <label style={{
            display: 'block',
            marginBottom: '8px',
            color: 'var(--text-primary)',
            fontWeight: '500',
            fontSize: '14px'
          }}>
            Phone number          </label>
          <div style={{ display: 'flex', gap: '8px', alignItems: 'center', flexWrap: 'nowrap' }}>
            <div style={{ position: 'relative', width: '120px', flexShrink: 0, minWidth: '120px' }}>
              <span
                style={{
                  position: 'absolute',
                  left: '12px',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  pointerEvents: 'none',
                  zIndex: 1,
                  display: 'flex',
                  alignItems: 'center',
                }}
              >
                <FlagIcon
                  countryCode={countries.find((c) => c.dialCode === countryCode)?.code || 'GH'}
                  size="1.1em"
                />
              </span>
              <CustomSelect
                name="countryCode"
                value={countryCode}
                onChange={(e) => setCountryCode(e.target.value)}
                options={countries.map((country) => ({
                  value: country.dialCode,
                  label: country.dialCode,
                  name: country.name,
                  countryCode: country.code,
                }))}
                searchable
                showCheckmark={false}
                style={{ width: '100%' }}
              />
            </div>
            <input
              type="tel"
              value={prepaidPhone}
              onChange={(e) => setPrepaidPhone(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && isValidGhanaPhone(prepaidPhone)) {
                  e.preventDefault();
                  handleVerify();
                }
              }}
              placeholder="e.g. 0244123456"
              className="input-large w-full"
              style={{ flex: 1 }}
            />
          </div>
          {!isVerified && isValidGhanaPhone(prepaidPhone) && !isVerifying && (
            <div style={{ marginTop: '8px', textAlign: 'right' }}>
              <button
                onClick={handleVerify}
                disabled={!isValidGhanaPhone(prepaidPhone)}
                className="btn secondary w-full utility-verify-btn"
                style={{}}
              >
                Verify
              </button>
            </div>
          )}
        </div>

        {/* Verification Status */}
        {isVerifying && (
          <div style={{ marginBottom: '12px' }}>
            <p className="utility-hint-text">Verifying meter details...</p>
          </div>
        )}

        {/* Verified Fields */}
        {isVerified && (
          <>
            {/* Meter Selection */}
            {customerDetails?.meters && customerDetails.meters.length > 0 && (
              <div style={{ marginBottom: '20px' }}>
                <label style={{
                  display: 'block',
                  marginBottom: '8px',
                  color: 'var(--text-primary)',
                  fontWeight: '500',
                  fontSize: '14px'
                }}>
                  {t('meterNumber', { ns: 'utilities' })}
                </label>
                <select
                  value={meterNumber}
                  onChange={(e) => setMeterNumber(e.target.value)}
                  className="input-large w-full"
                >
                  {customerDetails.meters.map((m) => (
                    <option key={m.id || m.value} value={m.value}>{m.display || m.value}</option>
                  ))}
                </select>
              </div>
            )}

            {/* Client Reference */}
            <div style={{ marginBottom: '20px' }}>
              <label style={{
                display: 'block',
                marginBottom: '8px',
                color: 'var(--text-primary)',
                fontWeight: '500',
                fontSize: '14px'
              }}>
                Client reference
              </label>
              <input
                type="text"
                value={clientReference}
                onChange={(e) => setClientReference(e.target.value)}
                placeholder="Enter client reference"
                className="input-large w-full"
              />
            </div>

            {/* Amount */}
            <div style={{ marginBottom: '20px' }}>
              <label style={{
                display: 'block',
                marginBottom: '8px',
                color: 'var(--text-primary)',
                fontWeight: '500',
                fontSize: '14px'
              }}>
                {t('amount', { ns: 'utilities' })} (GH₵)
              </label>
              <input
                type="number"
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
                placeholder={t('enterAmount', { ns: 'utilities' })}
                min="0"
                step="0.01"
                className="input-large w-full"
              />
            </div>

            {/* Customer Details */}
            <CustomerDetailsDisplay
              customerDetails={customerDetails}
              utilityType={UTILITY_PROVIDERS.ELECTRICITY}
            />
          </>
        )}
      </>

      {/* Payment Button */}
      <div style={{ textAlign: 'center', marginTop: '24px' }}>
        <button
          className="btn primary w-full"
          onClick={handlePayment}
          disabled={
            payElectricityMutation.isPending ||
            !isVerified || !meterNumber || !clientReference || !amount
          }
          style={{
            padding: '12px 16px',
            fontSize: '16px',
            fontWeight: '600',
          }}
        >
          {payElectricityMutation.isPending
            ? t('processing', { ns: 'utilities' })
            : `${t('pay', { ns: 'utilities' })} GH₵${amount || '0'}`
          }
        </button>
      </div>
    </div>
  );
};

export default ElectricityForm;

