/**
 * Utility Validators
 * 
 * Validation functions for utility forms.
 */

/**
 * Normalizes a Ghana phone number to the 233XXXXXXXXX format required by the API.
 * Accepts: 0XXXXXXXXX, 233XXXXXXXXX, +233XXXXXXXXX, or plain 9-digit XXXXXXXXX
 * Returns: 233XXXXXXXXX or the original value if it can't be normalized
 */
export const normalizeGhanaPhone = (value) => {
  if (!value) { return ''; }
  // Strip all spaces and dashes
  let digits = value.toString().replace(/[\s\-]/g, '');

  // Strip leading +
  if (digits.startsWith('+')) {
    digits = digits.slice(1);
  }

  // Already in 233XXXXXXXXX format (12 digits starting with 233)
  if (/^233\d{9}$/.test(digits)) {
    return digits;
  }

  // Starts with 0 (local format: 0XXXXXXXXX → 233XXXXXXXXX)
  if (/^0\d{9}$/.test(digits)) {
    return `233${digits.slice(1)}`;
  }

  // Just 9 digits (no prefix at all)
  if (/^\d{9}$/.test(digits)) {
    return `233${digits}`;
  }

  // Return as-is if we can't normalize — validation will catch it
  return digits;
};

/**
 * Validates a Ghana phone number.
 * Accepts local format (0XXXXXXXXX) or international format (233XXXXXXXXX / +233XXXXXXXXX).
 */
export const isValidGhanaPhone = (value) => {
  const normalized = normalizeGhanaPhone(value);
  return /^233\d{9}$/.test(normalized);
};

/**
 * Validates Ghana landline format (0 followed by 9 digits)
 */
export const isValidGhanaLandline = (value) => {
  return /^0\d{9}$/.test(value || '');
};

/**
 * Validates TV card number based on provider
 */
export const validateTvCardNumber = (accountNumber, provider) => {
  if (!accountNumber) {return { valid: false, error: 'Account number is required' };}

  const length = accountNumber.length;

  if (provider === 'DStv') {
    if (length < 10 || length > 11) {
      return { valid: false, error: 'DStv smart card number must be 10 or 11 digits' };
    }
  } else if (provider === 'GOtv') {
    if (length < 10 || length > 11) {
      return { valid: false, error: 'GOtv smart card number must be 10 or 11 digits' };
    }
  } else if (provider === 'StarTimes') {
    if (length !== 11) {
      return { valid: false, error: 'StarTimes smart card/account number must be exactly 11 digits' };
    }
  }

  return { valid: true };
};

