/**
 * useUtilityVerification Hook
 * 
 * Handles verification logic for all utility types.
 */

import { useState } from 'react';
import {
  verifyElectricityPrepaid,
  verifyWater,
  verifyInternet,
  verifyMtnBroadband,
  verifyTelecelBroadband,
  verifyTv,
} from '@/features/utilities/services/utilityService.js';
import { isValidGhanaLandline, isValidGhanaPhone } from '@/features/utilities/utils/validators.js';
import { validateTvCardNumber } from '@/features/utilities/utils/validators.js';
import { getFriendlyErrorMessage } from '@/features/utilities/utils/errors.js';

export const useUtilityVerification = () => {
  const [isVerifying, setIsVerifying] = useState(false);
  const [isVerified, setIsVerified] = useState(false);
  const [customerDetails, setCustomerDetails] = useState(null);

  const verify = async (utilityType, data, options = {}) => {
    const { onSuccess, onError } = options;
    setIsVerifying(true);
    setIsVerified(false);
    setCustomerDetails(null);

    try {
      let result;

      if (utilityType === 'electricity' && data.meterType === 'prepaid') {
        if (!data.phone) {
          throw new Error('Please enter a phone number first');
        }
        if (!isValidGhanaPhone(data.phone)) {
          throw new Error('Phone number must be in the format 233 followed by 9 digits (e.g., 233123456789)');
        }
        result = await verifyElectricityPrepaid(data.phone);
      } else if (utilityType === 'water') {
        if (!data.meterNumber) {throw new Error('Please enter a meter number first');}
        if (!data.phone) {throw new Error('Please enter a phone number for this water account');}
        if (!isValidGhanaPhone(data.phone)) {
          throw new Error('Phone number must be in the format 233 followed by 9 digits (e.g., 233123456789)');
        }
        result = await verifyWater(data.meterNumber, data.phone);
      } else if (utilityType === 'internet') {
        if (!data.network) {throw new Error('Please select a network first');}
        if (!data.phoneNumber) {throw new Error('Please enter a phone number first');}
        if (!isValidGhanaPhone(data.phoneNumber)) {
          throw new Error('Phone number must be in the format 233 followed by 9 digits (e.g., 233123456789)');
        }
        result = await verifyInternet(data.network, data.phoneNumber);
      } else if (utilityType === 'broadband' && data.network === 'MTN') {
        if (!data.destination) {throw new Error('Please enter a destination (landline) first');}
        if (!isValidGhanaLandline(data.destination)) {
          throw new Error('Landline must be in the format 0 followed by 9 digits (e.g., 0301234567)');
        }
        result = await verifyMtnBroadband(data.destination);
      } else if (utilityType === 'broadband' && data.network === 'Telecel') {
        if (!data.accountNumber) {throw new Error('Please enter a landline number first');}
        if (!isValidGhanaLandline(data.accountNumber)) {
          throw new Error('Landline must be in the format 0 followed by 9 digits (e.g., 0301234567)');
        }
        result = await verifyTelecelBroadband(data.accountNumber);
      } else if (utilityType === 'tv') {
        if (!data.network) {throw new Error('Please select a TV provider first');}
        if (!data.accountNumber) {throw new Error('Please enter a smart card/account number first');}
        
        const validation = validateTvCardNumber(data.accountNumber, data.network);
        if (!validation.valid) {
          throw new Error(validation.error);
        }
        result = await verifyTv(data.network, data.accountNumber);
      } else {
        throw new Error('Verification is only required for electricity, water, data bundles, broadband (MTN & Telecel), and TV at the moment.');
      }

      setCustomerDetails(result);
      setIsVerified(true);
      
      if (onSuccess) {
        onSuccess(result);
      }

      return result;
    } catch (error) {
      setIsVerified(false);
      setCustomerDetails(null);

      const friendlyMessage = getFriendlyErrorMessage(error);
      const normalizedError = error instanceof Error ? error : new Error(friendlyMessage);
      normalizedError.message = friendlyMessage;
      
      if (onError) {
        onError(normalizedError);
      }
      
      throw normalizedError;
    } finally {
      setIsVerifying(false);
    }
  };

  const reset = () => {
    setIsVerified(false);
    setCustomerDetails(null);
  };

  return {
    verify,
    isVerifying,
    isVerified,
    customerDetails,
    reset,
  };
};

export default useUtilityVerification;

