/**
 * Customer Details Display Component
 * 
 * Reusable component to display verified customer details.
 */

import React from 'react';

const CustomerDetailsDisplay = ({ customerDetails, utilityType }) => {
  if (!customerDetails) { return null; }

  const styles = {
    container: {
      marginTop: '16px',
      padding: '16px 20px',
      borderRadius: '8px',
      background: 'var(--bg-secondary)',
      border: '1px solid var(--border-primary)',
      textAlign: 'left',
      flex: '1 1 45%',
      maxWidth: '520px',
    },
    titleRow: {
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'space-between',
      marginBottom: '12px',
    },
    title: {
      margin: 0,
      fontWeight: 700,
      color: 'var(--text-primary)',
      fontSize: '1rem',
    },
    badge: {
      fontSize: '0.75rem',
      textTransform: 'uppercase',
      color: 'var(--accent)',
      backgroundColor: 'var(--accent-light, rgba(0, 72, 149, 0.1))',
      padding: '4px 8px',
      borderRadius: '999px',
      letterSpacing: '0.04em',
    },
    detailList: {
      listStyle: 'none',
      padding: 0,
      margin: 0,
      color: 'var(--text-primary)',
    },
    detailItem: {
      margin: '6px 0',
      fontSize: '0.95rem',
      color: 'var(--text-secondary)',
    },
    highlight: {
      fontWeight: 600,
      color: 'var(--text-primary)',
    },
    meterGrid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))',
      gap: '12px',
      marginTop: '12px',
    },
    meterCard: {
      borderRadius: '8px',
      border: '1px solid var(--border-primary)',
      backgroundColor: 'var(--card)',
      padding: '12px',
    },
    meterTitle: {
      margin: 0,
      fontWeight: 600,
      color: 'var(--text-primary)',
      fontSize: '0.95rem',
    },
    meterMeta: {
      margin: '6px 0 0 0',
      fontSize: '0.85rem',
      color: 'var(--text-muted)',
    },
  };

  const wrapperStyle = {
    display: 'flex',
    flexWrap: 'wrap',
    gap: '16px',
  };

  const hasValue = (value) => value !== '' && value !== null && value !== undefined;

  const formatCurrency = (value) => {
    if (value === '' || value === null || value === undefined) { return ''; }
    const numeric = Number(value);
    if (!Number.isNaN(numeric)) { return numeric.toFixed(2); }
    return String(value);
  };

  if (utilityType === 'electricity') {
    return (
      <div style={wrapperStyle}>
        <div style={styles.container}>
          <div style={styles.titleRow}>
            <p style={styles.title}>Customer Details</p>
            <span style={styles.badge}>Electricity</span>
          </div>
          <ul style={styles.detailList}>
            {customerDetails.name && (
              <li style={styles.detailItem}>
                <span style={styles.highlight}>Name:</span> {customerDetails.name}
              </li>
            )}
            {hasValue(customerDetails.meterBalance) && (
              <li style={styles.detailItem}>
                <span style={styles.highlight}>Balance:</span> GH₵{formatCurrency(customerDetails.meterBalance)}
              </li>
            )}
          </ul>
          {customerDetails.meters && customerDetails.meters.length > 0 && (
            <div style={{ marginTop: '16px', width: '100%' }}>
              <p style={{ ...styles.detailItem, ...styles.highlight, marginBottom: '8px' }}>
                Linked Meters ({customerDetails.meters.length})
              </p>
              <div style={styles.meterGrid}>
                {customerDetails.meters.map((meter, index) => (
                  <div key={meter.id || meter.value || index} style={styles.meterCard}>
                    <p style={styles.meterTitle}>{meter.display || `Meter ${index + 1}`}</p>
                    <p style={styles.meterMeta}>ID: {meter.value}</p>
                    {meter.amount !== null && meter.amount !== undefined && (
                      <p style={styles.meterMeta}>Last Balance: GH₵{formatCurrency(meter.amount)}</p>
                    )}
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  if (utilityType === 'water') {
    return (
      <div style={styles.container}>
        <div style={styles.titleRow}>
          <p style={styles.title}>Customer Details</p>
          <span style={styles.badge}>Water</span>
        </div>
        <ul style={styles.detailList}>
          {customerDetails.name && (
            <li style={styles.detailItem}>
              <span style={styles.highlight}>Name:</span> {customerDetails.name}
            </li>
          )}
          {customerDetails.amountDue && (
            <li style={styles.detailItem}>
              <span style={styles.highlight}>Amount Due:</span> GH₵{customerDetails.amountDue}
            </li>
          )}
          {customerDetails.sessionId && (
            <li style={styles.detailItem}>
              <span style={styles.highlight}>Session ID:</span> {customerDetails.sessionId}
            </li>
          )}
        </ul>
      </div>
    );
  }

  if (utilityType === 'broadband') {
    return (
      <div style={styles.container}>
        <div style={styles.titleRow}>
          <p style={styles.title}>Customer Details</p>
          <span style={styles.badge}>Broadband</span>
        </div>
        <ul style={styles.detailList}>
          {customerDetails.accountName && (
            <li style={styles.detailItem}>
              <span style={styles.highlight}>Account Name:</span> {customerDetails.accountName}
            </li>
          )}
          {customerDetails.accountId && (
            <li style={styles.detailItem}>
              <span style={styles.highlight}>Account ID:</span> {customerDetails.accountId}
            </li>
          )}
          {customerDetails.amountDue && (
            <li style={styles.detailItem}>
              <span style={styles.highlight}>Amount Due:</span> GH₵{customerDetails.amountDue}
            </li>
          )}
        </ul>
      </div>
    );
  }

  if (utilityType === 'tv') {
    return (
      <div style={styles.container}>
        <div style={styles.titleRow}>
          <p style={styles.title}>Customer Details</p>
          <span style={styles.badge}>TV</span>
        </div>
        <ul style={styles.detailList}>
          {customerDetails.accountName && (
            <li style={styles.detailItem}>
              <span style={styles.highlight}>Name:</span> {customerDetails.accountName}
            </li>
          )}
          {customerDetails.accountId && (
            <li style={styles.detailItem}>
              <span style={styles.highlight}>Account:</span> {customerDetails.accountId}
            </li>
          )}
          {customerDetails.amountDue !== undefined && customerDetails.amountDue !== '' && (
            <li style={styles.detailItem}>
              <span style={styles.highlight}>Amount Due:</span> GH₵{customerDetails.amountDue}
            </li>
          )}
        </ul>
      </div>
    );
  }

  return null;
};

export default CustomerDetailsDisplay;
