/**
 * Utility Service
 *
 * Handles all API calls for utility payments and verification.
 */

import { API_CONFIG } from '@/app/config/apiConfig.js';
import { getFriendlyErrorMessage } from '@/features/utilities/utils/errors.js';
import { getUserIdFromStorage } from '@/features/wallet/utils/walletHelpers.js';
import { tokenService } from '@/features/auth/services/tokenService.js';
import { normalizeGhanaPhone } from '@/features/utilities/utils/validators.js';
import logger from '@/shared/utils/logger.js';

const BASE_URL = API_CONFIG.UTILITY_BASE_URL;

const authenticatedFetch = async (url, options = {}) => {
  const token = tokenService.getToken();
  const headers = new Headers(options.headers || {});

  if (token && !headers.has('Authorization')) {
    headers.set('Authorization', `Bearer ${token}`);
  }

  // Automatically inject recipientid if missing
  if (!headers.has('recipientid')) {
    const recipientId = tokenService.getHeaderUserId();
    if (recipientId) {
      headers.set('recipientid', recipientId);
    }
  }

  return fetch(url, { ...options, headers });
};


const buildFriendlyError = async (response, fallbackMessage) => {
  let parsedBody = null;

  if (response) {
    try {
      const text = await response.text();
      if (text) {
        try {
          parsedBody = JSON.parse(text);
        } catch {
          parsedBody = text;
        }
      }
    } catch (error) {
      logger.warn('Failed to read error response body', { error });
    }
  }

  const message = getFriendlyErrorMessage(parsedBody, fallbackMessage);
  throw new Error(message);
};

/**
 * Verify electricity customer (prepaid)
 */
export const verifyElectricityPrepaid = async (phone) => {
  const normalizedPhone = normalizeGhanaPhone(phone);
  const queryUrl = `${BASE_URL}/buy-electricity/query?destination=${encodeURIComponent(normalizedPhone)}`;
  const response = await authenticatedFetch(queryUrl, { method: 'GET' });

  if (!response.ok) {
    await buildFriendlyError(response, 'Electricity lookup request failed');
  }

  const data = await response.json();
  //const meters = Array.isArray(data?.meters) ? data.meters : Array.isArray(data?.Meters) ? data.Meters : [];

  // , fixed normalization isssu, and data object thing.
  const rawMeters = Array.isArray(data?.data?.Data)
    ? data.data.Data
    : [];

  if (!rawMeters.length) {
    throw new Error('No meters found for this destination number');
  }

  const customerName = rawMeters[0]?.Display?.split('(')[0]?.trim() || 'Customer';

  const meters = rawMeters.map((meter, index) => {
    const value = meter?.Value || meter?.value || meter?.Id || meter?.id || '';
    const display = meter?.Display || meter?.display || (value ? `Meter ${value}` : `Meter ${index + 1}`);
    return {
      id: meter?.Id || meter?.id || value || `meter-${index}`,
      value,
      display,
      amount: meter?.Amount ?? meter?.amount ?? null,
    };
  });

  return {
    name: customerName,
    customerName: customerName,
    meters,
    meterBalance: rawMeters[0]?.Amount || 0,
    raw: data,
  };
};

/**
 * Verify water customer
 */
export const verifyWater = async (meterNumber, phone) => {
  const normalizedPhone = normalizeGhanaPhone(phone);
  const queryUrl = `${BASE_URL}/buy-water/query?destination=${encodeURIComponent(meterNumber)}&mobile=${encodeURIComponent(normalizedPhone)}`;
  const response = await authenticatedFetch(queryUrl, { method: 'GET' });

  if (!response.ok) {
    await buildFriendlyError(response, 'Water meter lookup request failed');
  }

  const data = await response.json();

  // Parse the new response structure: data.Data[].Display/Value
  const accountEntries = Array.isArray(data?.data?.Data) ? data.data.Data : [];

  const getField = (display) => {
    const entry = accountEntries.find(item => item?.Display === display);
    return entry?.Value || null;
  };

  const customerName = getField('name') || 'Customer';
  const amountDue = getField('amountDue') || '';
  const sessionId = getField('sessionId') || '';

  return {
    name: customerName,
    customerName,
    amountDue,
    sessionId,
    raw: data,
  };
};

/**
 * Verify internet/data bundles
 */
export const verifyInternet = async (network, phoneNumber) => {
  const normalizedPhone = normalizeGhanaPhone(phoneNumber);
  let queryUrl = '';
  if (network === 'MTN') {
    queryUrl = `${BASE_URL}/buy-mtn-data/query?destination=${encodeURIComponent(normalizedPhone)}`;
  } else if (network === 'Telecel') {
    queryUrl = `${BASE_URL}/buy-telecel-data/query?destination=${encodeURIComponent(normalizedPhone)}`;
  } else if (network === 'AT') {
    queryUrl = `${BASE_URL}/buy-at-data/query?destination=${encodeURIComponent(normalizedPhone)}`;
  } else {
    throw new Error('Unsupported network for data bundle verification');
  }

  const response = await authenticatedFetch(queryUrl, { method: 'GET' });
  if (!response.ok) {
    await buildFriendlyError(response, 'Data bundle lookup request failed');
  }

  const data = await response.json();
  const rawBundles =
    Array.isArray(data?.data?.bundles)
      ? data.data.bundles
      : Array.isArray(data?.bundles)
        ? data.bundles
        : Array.isArray(data?.Bundles)
          ? data.Bundles
          : [];

  logger.debug('Internet verification response', { data, rawBundles });

  if (!rawBundles.length) {
    throw new Error('No data bundles available for this number');
  }

  const bundles = rawBundles.map((b, index) => {
    const code =
      b?.value || b?.Value ||
      b?.code || b?.Code ||
      b?.bundleCode || b?.BundleCode ||
      b?.id || b?.Id ||
      `BUNDLE_${index}`;

    const displayCandidate =
      b?.display || b?.Display ||
      b?.label || b?.Label;

    const nameCandidate =
      b?.name || b?.Name ||
      b?.description || b?.Description ||
      b?.bundleName || b?.BundleName;

    const amount = b?.amount || b?.Amount || b?.price || b?.Price || null;

    const fallbackName = typeof nameCandidate === 'string'
      ? nameCandidate
      : `Bundle ${index + 1}`;

    const display = displayCandidate
      || fallbackName
      || (amount ? `Bundle ${index + 1} (GH₵${amount})` : `Bundle ${index + 1}`);

    return {
      code,
      value: code,
      name: fallbackName,
      display,
      amount,
    };
  });

  return { bundles, raw: data };
};

