/**
 * Verify TV account
 */
export const verifyTv = async (provider, accountNumber) => {
  let queryUrl = '';
  if (provider === 'DStv') {
    queryUrl = `${BASE_URL}/buy-dstv/query?destination=${encodeURIComponent(accountNumber)}`;
  } else if (provider === 'GOtv') {
    queryUrl = `${BASE_URL}/buy-gotv/query?destination=${encodeURIComponent(accountNumber)}`;
  } else if (provider === 'StarTimes') {
    queryUrl = `${BASE_URL}/buy-startimes/query?destination=${encodeURIComponent(accountNumber)}`;
  } else {
    throw new Error('Unsupported TV provider for verification');
  }

  const response = await authenticatedFetch(queryUrl, { method: 'GET' });
  if (!response.ok) {
    await buildFriendlyError(response, 'TV account lookup request failed');
  }

  const data = await response.json();

  const accountEntries = Array.isArray(data?.data?.accounts)
    ? data.data.accounts
    : Array.isArray(data?.accounts)
      ? data.accounts
      : [];

  const getField = (aliases) => {
    const normalizedAliases = aliases.map((alias) => alias.toLowerCase());
    for (const entry of accountEntries) {
      const key = (entry?.display ?? entry?.Display ?? '').toString().trim().toLowerCase();
      if (normalizedAliases.includes(key)) {
        const value = entry?.value ?? entry?.Value ?? '';
        return typeof value === 'string' ? value.trim() : value;
      }
    }
    return null;
  };

  const accountName = getField(['name', 'customer', 'accountname'])
    || data?.accountName
    || data?.AccountName
    || data?.customerName
    || data?.CustomerName
    || 'Customer';

  const accountId = getField(['account', 'account number', 'smartcard'])
    || data?.accountId
    || data?.AccountId
    || accountNumber;

  const amountRaw = getField(['amountdue', 'amount', 'due'])
    || data?.packageCost
    || data?.PackageCost
    || data?.amountDue
    || data?.AmountDue
    || '';

  const amountDue = amountRaw === '' || amountRaw === null
    ? ''
    : Number.isNaN(Number(amountRaw))
      ? amountRaw
      : Number(amountRaw);

  return {
    accountName,
    accountId,
    amountDue,
    raw: data,
  };
};

/**
 * Process electricity payment (prepaid)
 */
export const payElectricityPrepaid = async (payloadOrPhone, amount, clientReference, meterNumber) => {
  let phone = payloadOrPhone;
  if (payloadOrPhone && typeof payloadOrPhone === 'object') {
    phone = payloadOrPhone.phone;
    amount = payloadOrPhone.amount;
    clientReference = payloadOrPhone.clientReference;
    meterNumber = payloadOrPhone.meterNumber;
  }

  const payload = {
    Destination: normalizeGhanaPhone(phone),
    Amount: Number(amount),
    CallbackUrl: `${BASE_URL}/buy-electricity/callback`,
    ClientReference: clientReference,
    ProductCode: 'PD-006',
    Extradata: { bundle: meterNumber },
  };

  const response = await authenticatedFetch(`${BASE_URL}/buy-electricity`, {
    method: 'POST',
    headers: (() => {
      const recipientId = getUserIdFromStorage();
      const headers = { 'Content-Type': 'application/json' };
      if (recipientId) {
        headers.recipientid = recipientId;
      }
      return headers;
    })(),
    body: JSON.stringify(payload),
  });

  if (!response.ok) {
    await buildFriendlyError(response, 'Electricity payment request failed');
  }

  return response.json();
};

/**
 * Process internet/data payment
 */
export const payInternet = async (payloadOrNetwork, phoneNumber, amount, bundleCode) => {
  let network = payloadOrNetwork;
  if (payloadOrNetwork && typeof payloadOrNetwork === 'object') {
    network = payloadOrNetwork.network;
    phoneNumber = payloadOrNetwork.phoneNumber;
    amount = payloadOrNetwork.amount;
    bundleCode = payloadOrNetwork.bundleCode;
  }

  let baseRef = `DATA${Date.now()}`;
  let url, callbackUrl, productCode;

  if (network === 'MTN') {
    url = `${BASE_URL}/buy-mtn-data`;
    callbackUrl = `${BASE_URL}/buy-mtn-data/callback`;
    productCode = 'PD-010';
    baseRef = `MTND${Date.now()}`;
  } else if (network === 'Telecel') {
    url = `${BASE_URL}/buy-telecel-data`;
    callbackUrl = `${BASE_URL}/buy-telecel-data/callback`;
    productCode = 'PD-009';
    baseRef = `TEL${Date.now()}`;
  } else if (network === 'AT') {
    url = `${BASE_URL}/buy-at-data`;
    callbackUrl = `${BASE_URL}/buy-at-data/callback`;
    productCode = 'PD-008';
    baseRef = `DATA${Date.now()}`;
  } else {
    throw new Error('Unsupported network for data bundle purchase');
  }

  const payload = {
    Destination: normalizeGhanaPhone(phoneNumber),
    Amount: network === 'Telecel' ? String(amount) : Number(amount),
    CallbackUrl: callbackUrl,
    ClientReference: baseRef,
    ProductCode: productCode,
    Extradata: { bundle: bundleCode },
  };

  const response = await authenticatedFetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
  });

  if (!response.ok) {
    await buildFriendlyError(response, 'Data bundle purchase request failed');
  }

  return response.json();
};

