/**
 * Process water payment
 */
export const payWater = async (phone, meterNumber, amount, email, clientReference, sessionId) => {
  if (!sessionId) {
    throw new Error('Missing session ID from water lookup. Please verify the meter details again.');
  }

  const normalizedPhone = normalizeGhanaPhone(phone);
  const formattedAmount = Number.isNaN(Number(amount))
    ? amount
    : `GHS ${Number(amount).toFixed(2)}`;

  const payload = {
    Destination: meterNumber,
    Amount: Number(amount),
    CallbackUrl: `${BASE_URL}/buy-water/callback`,
    ClientReference: clientReference || `WATR${Date.now()}`,
    Extradata: {
      Bundle: formattedAmount,
      Email: email,
      SessionID: sessionId,
      Phone: normalizedPhone,
    },
    ProductCode: 'PD-004',
  };

  const response = await authenticatedFetch(`${BASE_URL}/buy-water`, {
    method: 'POST',
    headers: (() => {
      const recipientId = getUserIdFromStorage();
      const headers = { 'Content-Type': 'application/json' };
      if (recipientId) {
        headers.recipientid = recipientId;
      }
      return headers;
    })(),
    body: JSON.stringify(payload),
  });

  if (!response.ok) {
    await buildFriendlyError(response, 'Water payment request failed');
  }

  return response.json();
};

