/**
 * Process TV payment
 */
export const payTv = async (payloadOrProvider, accountNumber, amount, clientReference, bundle) => {
  let provider = payloadOrProvider;
  if (payloadOrProvider && typeof payloadOrProvider === 'object') {
    provider = payloadOrProvider.provider;
    accountNumber = payloadOrProvider.accountNumber;
    amount = payloadOrProvider.amount;
    clientReference = payloadOrProvider.clientReference;
    bundle = payloadOrProvider.bundle;
  }

  let url, callbackUrl, productCode;

  if (provider === 'DStv') {
    url = `${BASE_URL}/buy-dstv`;
    callbackUrl = `${BASE_URL}/buy-dstv/callback`;
    productCode = 'PD-001';
  } else if (provider === 'GOtv') {
    url = `${BASE_URL}/buy-gotv`;
    callbackUrl = `${BASE_URL}/buy-gotv/callback`;
    productCode = 'PD-002';
  } else if (provider === 'StarTimes') {
    url = `${BASE_URL}/buy-startimes`;
    callbackUrl = `${BASE_URL}/buy-startimes/callback`;
    productCode = 'PD-003';
  } else {
    throw new Error('Unsupported TV provider');
  }

  if (!clientReference) {
    throw new Error('Please provide a client reference for this TV payment.');
  }

  const payload = {
    Destination: accountNumber,
    Amount: Number(amount),
    CallbackUrl: callbackUrl,
    ClientReference: clientReference,
    ProductCode: productCode,
  };

  if (provider === 'DStv' || provider === 'GOtv' || provider === 'StarTimes') {
    payload.Extradata = { bundle: bundle || 'Standard' };
  }

  const response = await authenticatedFetch(url, {
    method: 'POST',
    headers: (() => {
      const recipientId = getUserIdFromStorage();
      const headers = { 'Content-Type': 'application/json' };
      if (recipientId) {
        headers.recipientid = recipientId;
      }
      return headers;
    })(),
    body: JSON.stringify(payload),
  });

  if (!response.ok) {
    await buildFriendlyError(response, 'TV payment request failed');
  }

  return response.json();
};

