import React, { useState, useEffect, useRef } from 'react';
import { useTranslation } from 'react-i18next';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { useUtilityVerification } from '@/features/utilities/hooks';
import { payInternet } from '@/features/utilities/services/utilityService.js';
import { isValidGhanaPhone } from '@/features/utilities/utils/validators.js';
import { NETWORKS, UTILITY_PROVIDERS } from '@/features/utilities/constants';
import { useMutation } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import { getFriendlyErrorMessage } from '@/features/utilities/utils/errors.js';
import logger from '@/shared/utils/logger.js';
import { countries } from '@/shared/utils/constants/countries-with-flags.js';
import { FlagIcon } from '@/shared/components';
import CustomSelect from '@/shared/components/CustomSelect.jsx';

const InternetDataForm = ({ onPaymentSuccess }) => {
  const { t } = useTranslation();
  const { success, error: showError } = useToast();
  const { verify, isVerifying, isVerified, customerDetails, reset } = useUtilityVerification();

  const [selectedNetwork, setSelectedNetwork] = useState('');
  const [phoneNumber, setPhoneNumber] = useState('');
  const [countryCode, setCountryCode] = useState('+233');
  const [bundleCode, setBundleCode] = useState('');
  const [amount, setAmount] = useState('');
  const [dataBundles, setDataBundles] = useState([]);

  // Track the last verified phone to detect actual changes
  const lastVerifiedPhone = useRef('');
  const lastVerifiedNetwork = useRef('');

  // Use React Query mutation for internet data payment
  const payInternetMutation = useMutation({
    mutationFn: async ({ network, phoneNumber: destination, bundleCode, amount }) => {
      return await payInternet({ network, phoneNumber: destination, bundleCode, amount });
    },
    invalidateQueries: [
      queryKeys.utilities.all(),
      queryKeys.dashboard.all(),
      queryKeys.wallet.balance(),
      queryKeys.reports.all(),
    ],
    onSuccess: () => {
      success(t('paymentProcessedSuccessfully', {
        ns: 'utilities',
        amount: parseFloat(amount).toLocaleString(),
        provider: selectedNetwork
      }));
      // Reset form
      setSelectedNetwork('');
      setPhoneNumber('');
      setBundleCode('');
      setAmount('');
      setDataBundles([]);
      lastVerifiedPhone.current = '';
      lastVerifiedNetwork.current = '';
      reset();
      if (onPaymentSuccess) {
        onPaymentSuccess();
      }
    },
    onError: (err) => {
      const fallback = t('paymentFailed', { ns: 'utilities', defaultValue: 'Payment failed. Please try again.' });
      showError(getFriendlyErrorMessage(err, fallback));
    },
  });

  // Reset when network changes
  const handleNetworkChange = (e) => {
    const newNetwork = e.target.value;
    setSelectedNetwork(newNetwork);
    // Clear everything when network changes
    reset();
    setBundleCode('');
    setAmount('');
    setDataBundles([]);
    setPhoneNumber('');
    lastVerifiedPhone.current = '';
    lastVerifiedNetwork.current = '';
  };


  const handleVerify = async () => {
    try {
      if (!selectedNetwork) {
        showError('Please select a network first');
        return;
      }
      if (!phoneNumber) {
        showError('Please enter a phone number first');
        return;
      }
      if (!isValidGhanaPhone(phoneNumber)) {
        showError('Please enter a valid Ghana phone number (e.g. 0244123456)');
        return;
      }

      const result = await verify(UTILITY_PROVIDERS.INTERNET, {
        network: selectedNetwork,
        phoneNumber,
      });

      logger.debug('Full verification result', { result });

      const bundles = Array.isArray(result?.bundles) ? result.bundles : [];

      if (bundles.length > 0) {
        logger.debug('First bundle structure', { firstBundle: bundles[0] });
        setDataBundles(bundles);
        lastVerifiedPhone.current = phoneNumber;
        lastVerifiedNetwork.current = selectedNetwork;
        success('Bundles loaded successfully');
      } else {
        showError('No data bundles available for this network');
        logger.error('Could not find bundles', { resultStructure: Object.keys(result || {}) });
      }

    } catch (error) {
      logger.error('Verification error', { error });
      showError(error.message || 'Failed to verify customer details. Please try again.');
    }
  };

  const handleBundleChange = (e) => {
    const code = e.target.value;
    setBundleCode(code);
    // Find the selected bundle and set the amount from its price/amount
    const selected = dataBundles.find(b => b.code === code);
    if (selected && selected.amount != null) {
      setAmount(String(selected.amount));
    } else if (selected && selected.price != null) {
      setAmount(String(selected.price));
    } else {
      setAmount('');
    }
  };

  const handlePayment = async () => {
    if (!selectedNetwork || !bundleCode || !phoneNumber || !amount) {
      showError('Please fill all required fields');
      return;
    }
    if (!isVerified) {
      showError('Please verify and select a bundle first');
      return;
    }

    payInternetMutation.mutate({
      network: selectedNetwork,
      phoneNumber,
      bundleCode,
      amount,
    });
  };

  return (
    <div>
      {/* Network Selection */}
      <div style={{ marginBottom: '20px' }}>
        <label style={{
          display: 'block',
          marginBottom: '8px',
          color: 'var(--text-primary)',
          fontWeight: '500',
          fontSize: '14px'
        }}>
          {t('selectPreferredNetwork', { ns: 'utilities' })}
        </label>
        <CustomSelect
          name="selectedNetwork"
          value={selectedNetwork}
          onChange={handleNetworkChange}
          options={[
            {
              value: NETWORKS.MTN,
              label: (
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                  <img src="/assets/mtnlogo.png" alt="MTN" style={{ width: 24, height: 24, objectFit: 'contain' }} />
                  <span>MTN</span>
                </div>
              )
            },
            {
              value: NETWORKS.TELECEL,
              label: (
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                  <img src="/assets/telecellogo.png" alt="Telecel" style={{ width: 24, height: 24, objectFit: 'contain' }} />
                  <span>Telecel</span>
                </div>
              )
            },
            {
              value: NETWORKS.AIRTELTIGO,
              label: (
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                  <img src="/assets/airtel-tigo.png" alt="AirtelTigo" style={{ width: 24, height: 24, objectFit: 'contain' }} />
                  <span>AirtelTigo</span>
                </div>
              )
            }
          ]}
          placeholder={t('chooseNetwork', { ns: 'utilities' })}
          style={{ 
            backgroundColor: 'var(--card)', 
            borderRadius: 'var(--radius-md)',
            border: '1px solid var(--border-secondary)'
          }}
          className="w-full"
        />
      </div>

      {/* Phone Number */}
      {selectedNetwork && (
        <div style={{ marginBottom: '20px' }}>
          <label style={{
            display: 'block',
            marginBottom: '8px',
            color: 'var(--text-primary)',
            fontWeight: '500',
            fontSize: '14px'
          }}>
            {t('phoneNumber', { ns: 'utilities' })}
          </label>
          <div style={{ display: 'flex', gap: '8px', alignItems: 'center', flexWrap: 'nowrap' }}>
            <div style={{ position: 'relative', width: '120px', flexShrink: 0, minWidth: '120px' }}>
              <span
                style={{
                  position: 'absolute',
                  left: '12px',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  pointerEvents: 'none',
                  zIndex: 1,
                  display: 'flex',
                  alignItems: 'center',
                }}
              >
                <FlagIcon
                  countryCode={countries.find((c) => c.dialCode === countryCode)?.code || 'GH'}
                  size="1.1em"
                />
              </span>
              <CustomSelect
                name="countryCode"
                value={countryCode}
                onChange={(e) => setCountryCode(e.target.value)}
                options={countries.map((country) => ({
                  value: country.dialCode,
                  label: country.dialCode,
                  name: country.name,
                  countryCode: country.code,
                }))}
                searchable
                showCheckmark={false}
                style={{ width: '100%' }}
              />
            </div>
            <input
              type="tel"
              value={phoneNumber}
              onChange={(e) => setPhoneNumber(e.target.value)}
              placeholder="e.g. 0244123456"
              className="input-large w-full"
              style={{ flex: 1 }}
            />
          </div>
          {!isVerified && selectedNetwork && phoneNumber && isValidGhanaPhone(phoneNumber) && !isVerifying && (
            <div style={{ marginTop: '8px', textAlign: 'right' }}>
              <button
                className="btn secondary"
                onClick={handleVerify}
                disabled={!phoneNumber || !isValidGhanaPhone(phoneNumber)}
              >
                Check bundles
              </button>
            </div>
          )}
        </div>
      )}

      {/* Verification Status */}
      {isVerifying && (
        <div style={{ marginBottom: '12px' }}>
          <p className="utility-hint-text">Verifying number and fetching available bundles...</p>
        </div>
      )}

      {/* Bundle Selection */}
      {isVerified && dataBundles.length > 0 && (
        <div style={{ marginBottom: '20px' }}>
          <label style={{
            display: 'block',
            marginBottom: '8px',
            color: 'var(--text-primary)',
            fontWeight: '500',
            fontSize: '14px'
          }}>
            {t('selectDataBundle', { ns: 'utilities', defaultValue: 'Select data bundle' })}
          </label>
          <select
            value={bundleCode}
            onChange={handleBundleChange}
            className="input-large w-full"
          >
            <option value="">{t('chooseBundle', { ns: 'utilities', defaultValue: 'Choose bundle' })}</option>
            {dataBundles.map((b) => (
              <option key={b.code} value={b.code}>
                {b.display || b.name} {b.amount ? `(GH₵${b.amount})` : b.price ? `(GH₵${b.price})` : ''}
              </option>
            ))}
          </select>
        </div>
      )}

      {/* Amount (read-only when bundle selected) */}
      {isVerified && bundleCode && (
        <div style={{ marginBottom: '20px' }}>
          <label style={{
            display: 'block',
            marginBottom: '8px',
            color: 'var(--text-primary)',
            fontWeight: '500',
            fontSize: '14px'
          }}>
            {t('amount', { ns: 'utilities' })} (GH₵)
          </label>
          <input
            type="number"
            value={amount}
            readOnly
            min="1"
            step="0.01"
            className="input-large w-full"
          />
        </div>
      )}

      {/* Payment Button */}
      {isVerified && bundleCode && amount && (
        <div style={{ textAlign: 'center', marginTop: '24px' }}>
          <button
            className="btn primary w-full"
            onClick={handlePayment}
            disabled={payInternetMutation.isPending}
            style={{
              padding: '14px 24px',
              fontSize: '16px',
              fontWeight: '600',
            }}
          >
            {payInternetMutation.isPending
              ? t('processing', { ns: 'utilities' })
              : `${t('pay', { ns: 'utilities' })} GH₵${amount || '0'}`
            }
          </button>
        </div>
      )}
    </div>
  );
};

export default InternetDataForm;