/**
 * TV Form Component
 * 
 * Form for cable TV bill payment supporting DStv, GOtv, and StarTimes.
 */

import React, { useState, useEffect, useRef } from 'react';
import { useTranslation } from 'react-i18next';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { useUtilityVerification } from '@/features/utilities/hooks';
import { payTv } from '@/features/utilities/services/utilityService.js';
import { validateTvCardNumber } from '@/features/utilities/utils/validators.js';
import { normalizeTvCardInput } from '@/features/utilities/utils/normalizers.js';
import { CustomerDetailsDisplay } from '@/features/utilities/components';
import { TV_PROVIDERS, UTILITY_PROVIDERS } from '@/features/utilities/constants';
import { useMutation } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import { getFriendlyErrorMessage } from '@/features/utilities/utils/errors.js';
import CustomSelect from '@/shared/components/CustomSelect.jsx';

const TvForm = ({ onPaymentSuccess }) => {
  const { t } = useTranslation();
  const { success, error: showError } = useToast();
  const { verify, isVerifying, isVerified, customerDetails, reset } = useUtilityVerification();

  const [selectedNetwork, setSelectedNetwork] = useState('');
  const [accountNumber, setAccountNumber] = useState('');
  const [amount, setAmount] = useState('');
  const [clientReference, setClientReference] = useState('');

  // Use React Query mutation for TV payment
  const payTvMutation = useMutation({
    mutationFn: async ({ provider, accountNumber, amount, clientReference }) => {
      return await payTv({ provider, accountNumber, amount, clientReference });
    },
    invalidateQueries: [
      queryKeys.utilities.all(),
      queryKeys.dashboard.all(),
      queryKeys.wallet.balance(),
      queryKeys.reports.all(),
    ],
    onSuccess: () => {
      success(t('paymentProcessedSuccessfully', {
        ns: 'utilities',
        amount: parseFloat(amount).toLocaleString(),
        provider: selectedNetwork
      }));
      // Reset form
      setSelectedNetwork('');
      setAccountNumber('');
      setAmount('');
      setClientReference('');
      reset();
      if (onPaymentSuccess) {
        onPaymentSuccess();
      }
    },
    onError: (err) => {
      const fallback = t('paymentFailed', { ns: 'utilities', defaultValue: 'Payment failed. Please try again.' });
      showError(getFriendlyErrorMessage(err, fallback));
    },
  });

  // Reset when network changes
  useEffect(() => {
    reset();
    setAccountNumber('');
    setAmount('');
    setClientReference('');
  }, [selectedNetwork]);

  // Reset verification when account number changes (but preserve if just filling other fields)
  const prevAccountRef = useRef('');

  useEffect(() => {
    const accountChanged = prevAccountRef.current !== accountNumber;

    // Only reset if account number actually changed from a previous non-empty value
    if (accountChanged && prevAccountRef.current !== '') {
      reset();
      setAmount('');
      setClientReference('');
    }

    prevAccountRef.current = accountNumber;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [accountNumber]);

  const handleVerify = async () => {
    try {
      if (!selectedNetwork) {
        showError('Please select a TV provider first');
        return;
      }
      if (!accountNumber) {
        showError('Please enter a smart card/account number first');
        return;
      }

      const validation = validateTvCardNumber(accountNumber, selectedNetwork);
      if (!validation.valid) {
        showError(validation.error);
        return;
      }

      const result = await verify(UTILITY_PROVIDERS.TV, {
        network: selectedNetwork,
        accountNumber,
      }, {
        onSuccess: (result) => {
          const derivedAmount = result.amountDue ?? result.packageCost;
          if (derivedAmount) {
            setAmount(String(derivedAmount));
          }
        },
        onError: (error) => {
          showError(error.message);
        },
      });

      if (result) {
        const derivedAmount = result.amountDue ?? result.packageCost;
        if (derivedAmount) {
          setAmount(String(derivedAmount));
        }
      }
    } catch (error) {
      showError(error.message || 'Failed to verify customer details. Please try again.');
    }
  };

  const handlePayment = async () => {
    if (!selectedNetwork || !accountNumber || !amount) {
      showError('Please fill all required fields');
      return;
    }
    if (!isVerified) {
      showError('Please verify customer details first');
      return;
    }
    if (!clientReference) {
      showError('Please provide a client reference');
      return;
    }

    payTvMutation.mutate({
      provider: selectedNetwork,
      accountNumber,
      amount,
      clientReference,
    });
  };

  return (
    <div>
      {/* TV Provider Selection */}
      <div style={{ marginBottom: '20px' }}>
        <label style={{
          display: 'block',
          marginBottom: '8px',
          color: 'var(--text-primary)',
          fontWeight: '500',
          fontSize: '14px'
        }}>
          {t('selectTvProvider', { ns: 'utilities' })}
        </label>
        <CustomSelect
          name="selectedNetwork"
          value={selectedNetwork}
          onChange={(e) => setSelectedNetwork(e.target.value)}
          options={[
            {
              value: TV_PROVIDERS.DSTV,
              label: (
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                  <span className="material-symbols-outlined" style={{ fontSize: '24px', color: '#004895' }}>live_tv</span>
                  <span>DStv</span>
                </div>
              )
            },
            {
              value: TV_PROVIDERS.GOTV,
              label: (
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                  <span className="material-symbols-outlined" style={{ fontSize: '24px', color: '#16a34a' }}>live_tv</span>
                  <span>GOtv</span>
                </div>
              )
            },
            {
              value: TV_PROVIDERS.STARTIMES,
              label: (
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                  <span className="material-symbols-outlined" style={{ fontSize: '24px', color: '#eab308' }}>live_tv</span>
                  <span>StarTimes</span>
                </div>
              )
            }
          ]}
          placeholder={t('chooseTvProvider', { ns: 'utilities' })}
          style={{ 
            backgroundColor: 'var(--card)', 
            borderRadius: 'var(--radius-md)',
            border: '1px solid var(--border-secondary)'
          }}
          className="w-full"
        />
      </div>

      {/* Smart Card / Account Number */}
      {selectedNetwork && (
        <div style={{ marginBottom: '20px' }}>
          <label style={{
            display: 'block',
            marginBottom: '8px',
            color: 'var(--text-primary)',
            fontWeight: '500',
            fontSize: '14px'
          }}>
            {t('smartCardAccountNumber', { ns: 'utilities' })} (Press Enter after typing the number)
          </label>
          <input
            type="text"
            value={accountNumber}
            onChange={(e) => setAccountNumber(normalizeTvCardInput(e.target.value, selectedNetwork))}
            onKeyDown={(e) => {
              if (e.key === 'Enter' && accountNumber) {
                e.preventDefault();
                handleVerify();
              }
            }}
            placeholder={t('enterSmartCardAccountNumber', { ns: 'utilities' })}
            className="input-large w-full"
          />
          {!isVerified && accountNumber && !isVerifying && (
            <div style={{ marginTop: '8px', textAlign: 'right' }}>
              <button
                className="btn secondary"
                onClick={handleVerify}
                disabled={!accountNumber}
              >
                Verify
              </button>
            </div>
          )}
        </div>
      )}

      {/* Verification Status */}
      {selectedNetwork && isVerifying && (
        <div style={{ marginBottom: '12px' }}>
          <p className="utility-hint-text">Verifying account details...</p>
        </div>
      )}

      {/* Verified Fields */}
      {selectedNetwork && isVerified && (
        <>
          {/* Amount (auto-filled, editable) */}
          <div style={{ marginBottom: '20px' }}>
            <label style={{
              display: 'block',
              marginBottom: '8px',
              color: 'var(--text-primary)',
              fontWeight: '500',
              fontSize: '14px'
            }}>
              {t('amount', { ns: 'utilities' })} (GH₵)
            </label>
            <input
              type="number"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              placeholder={t('enterAmount', { ns: 'utilities' })}
              min="1"
              step="0.01"
              className="input-large w-full"
            />
          </div>

          {/* Client Reference */}
          <div style={{ marginBottom: '20px' }}>
            <label style={{
              display: 'block',
              marginBottom: '8px',
              color: 'var(--text-primary)',
              fontWeight: '500',
              fontSize: '14px'
            }}>
              Client reference
            </label>
            <input
              type="text"
              value={clientReference}
              onChange={(e) => setClientReference(e.target.value)}
              placeholder="Enter reference e.g. TV12345"
              className="input-large w-full"
            />
          </div>

          {/* Customer Details */}
          <CustomerDetailsDisplay
            customerDetails={customerDetails}
            utilityType={UTILITY_PROVIDERS.TV}
          />
        </>
      )}

      {/* Payment Button */}
      {isVerified && (
        <div style={{ textAlign: 'center', marginTop: '24px' }}>
          <button
            className="btn primary w-full"
            onClick={handlePayment}
            disabled={
              payTvMutation.isPending ||
              !amount ||
              !clientReference
            }
            style={{
              padding: '14px 24px',
              fontSize: '16px',
              fontWeight: '600',
            }}
          >
            {payTvMutation.isPending
              ? t('processing', { ns: 'utilities' })
              : `${t('pay', { ns: 'utilities' })} GH₵${amount || '0'}`
            }
          </button>
        </div>
      )}
    </div>
  );
};

export default TvForm;
