/**
 * Utility Error Helpers
 *
 * Shared helpers for parsing backend error payloads and mapping them
 * to user-friendly messages across verification and payment flows.
 */

import logger from '@/shared/utils/logger.js';

const isJsonLike = (value) => {
  if (typeof value !== 'string') {return false;}
  const trimmed = value.trim();
  return (
    (trimmed.startsWith('{') && trimmed.endsWith('}')) ||
    (trimmed.startsWith('[') && trimmed.endsWith(']'))
  );
};

export const parseErrorPayload = (input) => {
  if (!input) {return null;}

  if (input instanceof Error) {
    return input.message;
  }

  if (typeof input === 'string') {
    if (isJsonLike(input)) {
      try {
        const parsed = JSON.parse(input);
        return (
          parsed?.message ||
          parsed?.Message ||
          parsed?.label ||
          parsed?.Label ||
          parsed?.error ||
          parsed?.Error ||
          null
        );
      } catch (error) {
        logger.warn('Failed to parse error payload', { error });
        return input.trim();
      }
    }

    return input.trim();
  }

  if (typeof input === 'object') {
    return (
      input?.message ||
      input?.Message ||
      input?.label ||
      input?.Label ||
      input?.error ||
      input?.Error ||
      null
    );
  }

  return null;
};

export const getFriendlyErrorMessage = (
  input,
  fallbackMessage = 'Something went wrong. Please try again.'
) => {
  const message = parseErrorPayload(input) || fallbackMessage;
  const normalized = message.toLowerCase();

  if (normalized.includes('insufficient wallet balance')) {
    return 'Insufficient wallet balance. Please top up your wallet and try again.';
  }

  if (normalized.includes('invalid destination') || normalized.includes('phone number')) {
    return 'The phone number entered seems invalid. Please confirm the number and try again.';
  }

  if (normalized.includes('phone') && (normalized.includes('not found') || normalized.includes('no record') || normalized.includes('not linked'))) {
    return 'This phone number is not linked to any electricity meter. Please verify the number or contact the electricity company.';
  }
  
  if (normalized.includes('request failed with status code 400')) {
    return 'The request could not be processed. Please verify your details and try again.';
  }

  if (normalized.includes('timeout')) {
    return 'The request took too long to complete. Please check your connection and try again.';
  }

  if (normalized.includes('not found') || normalized.includes('no record')) {
    return 'We could not find records for the details provided. Please double-check and try again.';
  }

  return message;
};
