/**
 * Utility Selector Component
 * 
 * Displays a grid of utility providers for user selection.
 */

import React from 'react';
import { useTranslation } from 'react-i18next';
import { getUtilityProviders } from '@/features/utilities/constants';
import ecgLogo from '@/assets/ECG.png';
import gwcLogo from '@/assets/GWC.png';
import databundlesLogo from '@/assets/Databundles.png';
import broadbandLogo from '@/assets/Broadband.png';
import cabletvLogo from '@/assets/Cabletv.png';

const UtilitySelector = ({ selectedUtility, onSelectUtility, windowWidth, disabled = false }) => {
  const { t } = useTranslation();
  const utilityProviders = getUtilityProviders(t);

  const handleCardClick = (providerId) => {
    if (disabled) {return;}

    // Prevent multiple rapid clicks
    const card = document.querySelector(`[data-utility-id="${providerId}"]`);
    if (card) {
      card.style.pointerEvents = 'none';
      setTimeout(() => {
        if (card) {card.style.pointerEvents = '';}
      }, 300);
    }

    onSelectUtility(providerId);
  };

  return (
    <div className="utility-selector">
      <div className="utility-grid">
        {utilityProviders.map((provider) => (
          <div
            key={provider.id}
            data-tour={`utilities-provider-${provider.id}`}
            data-utility-id={provider.id}
            onClick={() => handleCardClick(provider.id)}
            className={`utility-card ${selectedUtility === provider.id ? 'utility-card--selected' : ''} ${disabled ? 'utility-card--disabled' : ''}`}
            role="button"
            tabIndex={disabled ? -1 : 0}
            aria-label={`${provider.name} - ${provider.description}`}
            aria-disabled={disabled}
            onKeyDown={(e) => {
              if ((e.key === 'Enter' || e.key === ' ') && !disabled) {
                e.preventDefault();
                handleCardClick(provider.id);
              }
            }}
          >
            <div className="utility-card-icon-container">
              {provider.id === 'electricity' ? (
                <img
                  src={ecgLogo}
                  alt={provider.name}
                  className="utility-card-logo"
                />
              ) : provider.id === 'water' ? (
                <img
                  src={gwcLogo}
                  alt={provider.name}
                  className="utility-card-logo"
                />
              ) : provider.id === 'internet' ? (
                <img
                  src={databundlesLogo}
                  alt={provider.name}
                  className="utility-card-logo"
                />
              ) : provider.id === 'phone' ? (
                <img
                  src={databundlesLogo}
                  alt={provider.name}
                  className="utility-card-logo"
                />
              ) : provider.id === 'broadband' ? (
                <img
                  src={broadbandLogo}
                  alt={provider.name}
                  className="utility-card-logo"
                />
              ) : provider.id === 'tv' ? (
                <img
                  src={cabletvLogo}
                  alt={provider.name}
                  className="utility-card-logo"
                />
              ) : (
                <span className="material-symbols-outlined utility-card-icon">
                  {provider.icon}
                </span>
              )}
            </div>
            <div className="utility-card-content">
              <h5 className="utility-card-title">
                {provider.name}
              </h5>
              <p className="utility-card-description">
                {provider.description}
              </p>
            </div>
            <div className="utility-card-arrow">
              <span className="material-symbols-outlined">arrow_forward</span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default UtilitySelector;

