/**
 * Payment Details Modal Component
 * 
 * Modal dialog for utility payment details that replaces the inline form display.
 * Shows the payment form in a centered popup with proper overlay and animations.
 */

import React from 'react';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';
import { LoadingSpinner } from '@/shared/components';

const PaymentDetailsModal = ({
  isOpen,
  onClose,
  selectedUtility,
  isFormLoading,
  error,
  children,
  title
}) => {
  const { t } = useTranslation();

  if (!isOpen) { return null; }

  return createPortal(
    <div className="utility-modal-overlay">
      <div className="utility-modal-container">
        {/* Header */}
        <div className="utility-modal-header">
          <div style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between'
          }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
              <span className="material-symbols-outlined" style={{
                fontSize: '28px',
                color: 'var(--accent)'
              }}>
                payment
              </span>
              <div>
                <h2 style={{
                  margin: 0,
                  fontSize: '20px',
                  fontWeight: '700',
                  color: 'var(--text-primary)'
                }}>
                  {title || t('paymentDetails', { ns: 'utilities' })}
                </h2>
                <p style={{
                  margin: '4px 0 0 0',
                  fontSize: '14px',
                  color: 'var(--text-muted)'
                }}>
                  {selectedUtility && t(`utilityType.${selectedUtility}`, {
                    ns: 'utilities',
                    defaultValue: selectedUtility
                  })}
                </p>
              </div>
            </div>
            <button
              onClick={onClose}
              disabled={isFormLoading}
              style={{
                background: 'none',
                border: 'none',
                cursor: isFormLoading ? 'not-allowed' : 'pointer',
                color: isFormLoading ? 'var(--text-muted)' : 'var(--text-secondary)',
                padding: '4px',
                borderRadius: '4px',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                transition: 'all var(--transition-base)',
                opacity: isFormLoading ? 0.5 : 1
              }}
              onMouseEnter={(e) => {
                if (!isFormLoading) {
                  e.currentTarget.style.backgroundColor = 'var(--bg-hover)';
                  e.currentTarget.style.color = 'var(--text-primary)';
                }
              }}
              onMouseLeave={(e) => {
                if (!isFormLoading) {
                  e.currentTarget.style.backgroundColor = 'transparent';
                  e.currentTarget.style.color = 'var(--text-secondary)';
                }
              }}
              title={t('closeForm', { ns: 'utilities' })}
            >
              <span className="material-symbols-outlined" style={{ fontSize: '24px', pointerEvents: 'none' }}>
                close
              </span>
            </button>
          </div>
        </div>

        {/* Content */}
        <div className="utility-modal-body">
          {error && (
            <div style={{
              display: 'flex',
              alignItems: 'center',
              gap: '12px',
              padding: '16px',
              backgroundColor: 'var(--error-bg)',
              border: '1px solid var(--error)',
              borderRadius: '8px',
              marginBottom: '20px'
            }}>
              <span className="material-symbols-outlined" style={{
                fontSize: '20px',
                color: 'var(--error)'
              }}>
                error
              </span>
              <span style={{ color: 'var(--error)', fontSize: '14px' }}>
                {error}
              </span>
            </div>
          )}

          {isFormLoading && (
            <div style={{
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              justifyContent: 'center',
              padding: '40px',
              gap: '16px'
            }}>
              <LoadingSpinner size="large" />
              <span style={{ color: 'var(--text-secondary)', fontSize: '14px' }}>
                {t('loading', { ns: 'common' })}
              </span>
            </div>
          )}

          {!isFormLoading && !error && children}
        </div>
      </div>
    </div>,
    document.body
  );
};

export default PaymentDetailsModal;
