/**
 * Water Form Component
 * 
 * Form for Ghana Water Company bill payment.
 */

import React, { useState, useEffect, useRef } from 'react';
import { useTranslation } from 'react-i18next';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { useUtilityVerification } from '@/features/utilities/hooks';
import { payWater } from '@/features/utilities/services/utilityService.js';
import { isValidGhanaPhone } from '@/features/utilities/utils/validators.js';
import { normalizeMeterInput } from '@/features/utilities/utils/normalizers.js';
import { CustomerDetailsDisplay } from '@/features/utilities/components';
import { UTILITY_PROVIDERS } from '@/features/utilities/constants';
import { useMutation } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import { getFriendlyErrorMessage } from '@/features/utilities/utils/errors.js';
import { countries } from '@/shared/utils/constants/countries-with-flags.js';
import { FlagIcon } from '@/shared/components';
import CustomSelect from '@/shared/components/CustomSelect.jsx';

const WaterForm = ({ onPaymentSuccess }) => {
  const { t } = useTranslation();
  const { success, error: showError } = useToast();
  const { verify, isVerifying, isVerified, customerDetails, reset } = useUtilityVerification();

  const [meterNumber, setMeterNumber] = useState('');
  const [waterPhone, setWaterPhone] = useState('');
  const [countryCode, setCountryCode] = useState('+233');
  const [amount, setAmount] = useState('');
  const [waterEmail, setWaterEmail] = useState('');
  const [clientReference, setClientReference] = useState('');
  const [waterSessionId, setWaterSessionId] = useState('');

  // Use React Query mutation for water payment
  const payWaterMutation = useMutation({
    mutationFn: async ({ phone, meterNumber, amount, email, clientReference, sessionId }) => {
      return await payWater(phone, meterNumber, amount, email, clientReference, sessionId);
    },
    invalidateQueries: [
      queryKeys.utilities.all(),
      queryKeys.dashboard.all(),
      queryKeys.wallet.balance(),
      queryKeys.reports.all(),
    ],
    onSuccess: () => {
      success(t('paymentProcessedSuccessfully', {
        ns: 'utilities',
        amount: parseFloat(amount).toLocaleString(),
        provider: 'Ghana Water Company (GWC)'
      }));
      // Reset form
      setMeterNumber('');
      setWaterPhone('');
      setAmount('');
      setWaterEmail('');
      setClientReference('');
      setWaterSessionId('');
      reset();
      if (onPaymentSuccess) {
        onPaymentSuccess();
      }
    },
    onError: (err) => {
      const fallback = t('paymentFailed', { ns: 'utilities', defaultValue: 'Payment failed. Please try again.' });
      showError(getFriendlyErrorMessage(err, fallback));
    },
  });

  // Reset verification when identifying fields change
  // Store previous values to detect actual changes (not just initial render)
  const prevMeterRef = useRef('');
  const prevPhoneRef = useRef('');

  useEffect(() => {
    const meterChanged = prevMeterRef.current !== meterNumber;
    const phoneChanged = prevPhoneRef.current !== waterPhone;

    // Only reset if values actually changed from a previous non-empty value
    // This prevents reset on initial render or when user is just filling other fields
    if ((meterChanged || phoneChanged) && (prevMeterRef.current !== '' || prevPhoneRef.current !== '')) {
      reset();
      setAmount('');
      setWaterEmail('');
      setClientReference('');
      setWaterSessionId('');
    }

    // Update refs for next comparison
    prevMeterRef.current = meterNumber;
    prevPhoneRef.current = waterPhone;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [meterNumber, waterPhone]);

  const handleVerify = async () => {
    try {
      if (!meterNumber) {
        showError('Please enter a meter number first');
        return;
      }
      if (!waterPhone) {
        showError('Please enter a phone number for this water account');
        return;
      }
      if (!isValidGhanaPhone(waterPhone)) {
        showError('Please enter a valid Ghana phone number (e.g. 0244123456)');
        return;
      }

      const result = await verify(UTILITY_PROVIDERS.WATER, {
        meterNumber,
        phone: waterPhone,
      }, {
        onSuccess: (result) => {
          if (result.amountDue) {
            setAmount(String(result.amountDue));
          }
          if (result.sessionId) {
            setWaterSessionId(result.sessionId);
          }
        },
        onError: (error) => {
          showError(error.message);
        },
      });

      if (result) {
        if (result.amountDue) {
          setAmount(String(result.amountDue));
        }
        if (result.sessionId) {
          setWaterSessionId(result.sessionId);
        }
      }
    } catch (error) {
      showError(error.message || 'Failed to verify customer details. Please try again.');
    }
  };

  const handlePayment = async () => {
    if (!meterNumber || !waterPhone || !amount || !waterEmail || !clientReference) {
      showError('Please fill all required fields');
      return;
    }
    if (!isVerified) {
      showError('Please verify customer details first');
      return;
    }
    if (!waterSessionId) {
      showError('Missing session ID. Please verify the meter details again.');
      return;
    }

    payWaterMutation.mutate({
      phone: waterPhone,
      meterNumber: meterNumber,
      amount: amount,
      email: waterEmail,
      clientReference: clientReference,
      sessionId: waterSessionId,
    });
  };

  return (
    <div>
      {/* Meter Number */}
      <div style={{ marginBottom: '20px' }}>
        <label style={{
          display: 'block',
          marginBottom: '8px',
          color: 'var(--text-primary)',
          fontWeight: '500',
          fontSize: '14px'
        }}>
          {t('meterNumber', { ns: 'utilities' })}
        </label>
        <input
          type="text"
          value={meterNumber}
          onChange={(e) => setMeterNumber(normalizeMeterInput(e.target.value))}
          onKeyDown={(e) => {
            if (e.key === 'Enter' && meterNumber && waterPhone && isValidGhanaPhone(waterPhone)) {
              e.preventDefault();
              handleVerify();
            }
          }}
          placeholder={t('enterWaterMeterNumber', { ns: 'utilities' })}
          className="input-large w-full"
        />
      </div>

      {/* Phone Number */}
      <div style={{ marginBottom: '20px' }}>
        <label style={{
          display: 'block',
          marginBottom: '8px',
          color: 'var(--text-primary)',
          fontWeight: '500',
          fontSize: '14px'
        }}>
          Phone number for this water account
        </label>
          <div style={{ display: 'flex', gap: '8px', alignItems: 'center', flexWrap: 'nowrap' }}>
            <div style={{ position: 'relative', width: '120px', flexShrink: 0, minWidth: '120px' }}>
              <span
                style={{
                  position: 'absolute',
                  left: '12px',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  pointerEvents: 'none',
                  zIndex: 1,
                  display: 'flex',
                  alignItems: 'center',
                }}
              >
                <FlagIcon
                  countryCode={countries.find((c) => c.dialCode === countryCode)?.code || 'GH'}
                  size="1.1em"
                />
              </span>
              <CustomSelect
                name="countryCode"
                value={countryCode}
                onChange={(e) => setCountryCode(e.target.value)}
                options={countries.map((country) => ({
                  value: country.dialCode,
                  label: country.dialCode,
                  name: country.name,
                  countryCode: country.code,
                }))}
                searchable
                showCheckmark={false}
                style={{ width: '100%' }}
              />
            </div>
            <input
              type="tel"
              value={waterPhone}
              onChange={(e) => setWaterPhone(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && meterNumber && waterPhone && isValidGhanaPhone(waterPhone)) {
                  e.preventDefault();
                  handleVerify();
                }
              }}
              placeholder="e.g. 0244123456"
              className="input-large w-full"
              style={{ flex: 1 }}
            />
          </div>
        {!isVerified && meterNumber && isValidGhanaPhone(waterPhone) && !isVerifying && (
          <div style={{ marginTop: '8px', textAlign: 'right' }}>
            <button
              onClick={handleVerify}
              disabled={!meterNumber || !isValidGhanaPhone(waterPhone)}
              className="btn secondary w-full utility-verify-btn"
              style={{}}
            >
              Verify
            </button>
          </div>
        )}
      </div>

      {isVerifying && (
        <div style={{ marginBottom: '12px' }}>
          <p className="utility-hint-text">Verifying meter details...</p>
        </div>
      )}

      {!isVerifying && meterNumber && waterPhone && (
        <p className="utility-hint-text" style={{ margin: '-12px 0 12px 0' }}>
          Tip: Press Enter in either field after filling both meter number and phone number
        </p>
      )}

      {/* Verified Fields */}
      {isVerified && (
        <>
          {/* Amount (auto-filled, read-only) */}
          <div style={{ marginBottom: '20px' }}>
            <label style={{
              display: 'block',
              marginBottom: '8px',
              color: 'var(--text-primary)',
              fontWeight: '500',
              fontSize: '14px'
            }}>
              {t('amount', { ns: 'utilities' })} (GH₵)
            </label>
            <input
              type="number"
              value={amount}
              readOnly
              min="1"
              step="0.01"
              className="input-large w-full"
            />
          </div>

          {/* Session ID (auto-filled, read-only) */}
          <div style={{ marginBottom: '20px' }}>
            <label style={{
              display: 'block',
              marginBottom: '8px',
              color: 'var(--text-primary)',
              fontWeight: '500',
              fontSize: '14px'
            }}>
              Session ID
            </label>
            <input
              type="text"
              value={customerDetails?.sessionId || ''}
              readOnly
              className="input-large w-full"
              style={{ backgroundColor: 'var(--bg-secondary)' }}
              placeholder="Session ID will appear after verification"
            />
          </div>

          {/* Email */}
          <div style={{ marginBottom: '20px' }}>
            <label style={{
              display: 'block',
              marginBottom: '8px',
              color: 'var(--text-primary)',
              fontWeight: '500',
              fontSize: '14px'
            }}>
              Email
            </label>
            <input
              type="email"
              value={waterEmail}
              onChange={(e) => setWaterEmail(e.target.value)}
              placeholder="Enter email for receipt"
              className="input-large w-full"
            />
          </div>

          {/* Client Reference */}
          <div style={{ marginBottom: '20px' }}>
            <label style={{
              display: 'block',
              marginBottom: '8px',
              color: 'var(--text-primary)',
              fontWeight: '500',
              fontSize: '14px'
            }}>
              Client reference
            </label>
            <input
              type="text"
              value={clientReference}
              onChange={(e) => setClientReference(e.target.value)}
              placeholder="Enter client reference"
              className="input-large"
              style={{ width: '100%' }}
            />
          </div>

          {/* Customer Details */}
          <CustomerDetailsDisplay
            customerDetails={customerDetails}
            utilityType={UTILITY_PROVIDERS.WATER}
          />
        </>
      )}

      {/* Payment Button */}
      {isVerified && (
        <div style={{ textAlign: 'center', marginTop: '24px' }}>
          <button
            className="btn primary w-full"
            onClick={handlePayment}
            disabled={payWaterMutation.isPending || !waterEmail || !clientReference || !amount}
            style={{
              padding: '12px 16px',
              fontSize: '16px',
              fontWeight: '600',
            }}
          >
            {payWaterMutation.isPending
              ? t('processing', { ns: 'utilities' })
              : `${t('pay', { ns: 'utilities' })} GH₵${amount || '0'}`
            }
          </button>
        </div>
      )}
    </div>
  );
};

export default WaterForm;

