/**
 * Broadband Form Component
 * 
 * Form for broadband bill payment supporting MTN and Telecel networks.
 */

import React, { useState, useEffect, useRef } from 'react';
import { useTranslation } from 'react-i18next';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { useUtilityVerification } from '@/features/utilities/hooks';
import { payMtnBroadband, payTelecelBroadband } from '@/features/utilities/services/utilityService.js';
import { isValidGhanaLandline } from '@/features/utilities/utils/validators.js';
import { CustomerDetailsDisplay } from '@/features/utilities/components';
import { NETWORKS, UTILITY_PROVIDERS } from '@/features/utilities/constants';
import { useMutation } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import { getFriendlyErrorMessage } from '@/features/utilities/utils/errors.js';
import CustomSelect from '@/shared/components/CustomSelect.jsx';

const BroadbandForm = ({ onPaymentSuccess }) => {
  const { t } = useTranslation();
  const { success, error: showError } = useToast();
  const { verify, isVerifying, isVerified, customerDetails, reset } = useUtilityVerification();

  const [selectedNetwork, setSelectedNetwork] = useState('');
  const [broadbandDestination, setBroadbandDestination] = useState('');
  const [accountNumber, setAccountNumber] = useState('');
  const [bundleValue, setBundleValue] = useState('');
  const [amount, setAmount] = useState('');
  const [mtnBroadbandBundles, setMtnBroadbandBundles] = useState([]);

  // Use React Query mutation for broadband payment
  const payBroadbandMutation = useMutation({
    mutationFn: async ({ network, params }) => {
      if (network === NETWORKS.MTN) {
        return await payMtnBroadband({ destination: params.destination, bundleValue: params.bundleValue, amount: params.amount });
      }
      return await payTelecelBroadband({ accountNumber: params.accountNumber, bundleValue: params.bundleValue, amount: params.amount });
    },
    invalidateQueries: [
      queryKeys.utilities.all(),
      queryKeys.dashboard.all(),
      queryKeys.wallet.balance(),
      queryKeys.reports.all(),
    ],
    onSuccess: () => {
      success(t('paymentProcessedSuccessfully', {
        ns: 'utilities',
        amount: parseFloat(amount).toLocaleString(),
        provider: selectedNetwork
      }));
      // Reset form
      setSelectedNetwork('');
      setBroadbandDestination('');
      setAccountNumber('');
      setBundleValue('');
      setAmount('');
      setMtnBroadbandBundles([]);
      reset();
      if (onPaymentSuccess) {
        onPaymentSuccess();
      }
    },
    onError: (err) => {
      const fallback = t('paymentFailed', { ns: 'utilities', defaultValue: 'Payment failed. Please try again.' });
      showError(getFriendlyErrorMessage(err, fallback));
    },
  });

  // Reset when network changes
  useEffect(() => {
    reset();
    setBroadbandDestination('');
    setAccountNumber('');
    setBundleValue('');
    setAmount('');
    setMtnBroadbandBundles([]);
  }, [selectedNetwork]);

  // Reset verification when identifying fields change (but preserve if just selecting bundle)
  const prevDestinationRef = useRef('');
  const prevAccountRef = useRef('');

  useEffect(() => {
    const destinationChanged = prevDestinationRef.current !== broadbandDestination;
    const accountChanged = prevAccountRef.current !== accountNumber;

    // Only reset if values actually changed from a previous non-empty value
    if (selectedNetwork === NETWORKS.MTN && destinationChanged && prevDestinationRef.current !== '') {
      reset();
      setBundleValue('');
      setAmount('');
      setMtnBroadbandBundles([]);
    } else if (selectedNetwork === NETWORKS.TELECEL && accountChanged && prevAccountRef.current !== '') {
      reset();
      setAmount('');
    }

    prevDestinationRef.current = broadbandDestination;
    prevAccountRef.current = accountNumber;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [broadbandDestination, accountNumber, selectedNetwork]);

  const handleVerify = async () => {
    try {
      if (selectedNetwork === NETWORKS.MTN) {
        if (!broadbandDestination) {
          showError('Please enter a destination (landline) first');
          return;
        }
        if (!isValidGhanaLandline(broadbandDestination)) {
          showError('Landline must be in the format 0 followed by 9 digits (e.g., 0301234567)');
          return;
        }

        const result = await verify(UTILITY_PROVIDERS.BROADBAND, {
          network: NETWORKS.MTN,
          destination: broadbandDestination,
        }, {
          onSuccess: (result) => {
            if (result.bundles) {
              setMtnBroadbandBundles(result.bundles);
            }
          },
          onError: (error) => {
            showError(error.message);
          },
        });

        if (result && result.bundles) {
          setMtnBroadbandBundles(result.bundles);
        }
      } else if (selectedNetwork === NETWORKS.TELECEL) {
        if (!accountNumber) {
          showError('Please enter a landline number first');
          return;
        }
        if (!isValidGhanaLandline(accountNumber)) {
          showError('Landline must be in the format 0 followed by 9 digits (e.g., 0301234567)');
          return;
        }

        const result = await verify(UTILITY_PROVIDERS.BROADBAND, {
          network: NETWORKS.TELECEL,
          accountNumber,
        }, {
          onSuccess: (result) => {
            if (result.amountDue) {
              setAmount(String(result.amountDue));
            }
          },
          onError: (error) => {
            showError(error.message);
          },
        });

        if (result && result.amountDue) {
          setAmount(String(result.amountDue));
        }
      }
    } catch (error) {
      showError(error.message || 'Failed to verify customer details. Please try again.');
    }
  };

  const handleBundleChange = (e) => {
    const code = e.target.value;
    const selected = mtnBroadbandBundles.find(b => b.code === code);
    const nextBundleValue = selected?.name || selected?.code || '';
    setBundleValue(nextBundleValue);
    if (selected && selected.price != null) {
      setAmount(String(selected.price));
    }
  };

  const handlePayment = async () => {
    if (!selectedNetwork) {
      showError('Please select a network');
      return;
    }
    if (!isVerified) {
      showError('Please verify customer details first');
      return;
    }

    if (selectedNetwork === NETWORKS.MTN) {
      if (!broadbandDestination || !bundleValue || !amount) {
        showError('Please fill all required fields');
        return;
      }
    } else if (selectedNetwork === NETWORKS.TELECEL) {
      if (!accountNumber || !bundleValue || !amount) {
        showError('Please fill all required fields');
        return;
      }
    }

    if (selectedNetwork === NETWORKS.MTN) {
      payBroadbandMutation.mutate({
        network: NETWORKS.MTN,
        params: {
          destination: broadbandDestination,
          bundleValue: bundleValue,
          amount: amount,
        },
      });
    } else if (selectedNetwork === NETWORKS.TELECEL) {
      payBroadbandMutation.mutate({
        network: NETWORKS.TELECEL,
        params: {
          accountNumber: accountNumber,
          bundleValue: bundleValue,
          amount: amount,
        },
      });
    }
  };

  return (
    <div>
      {/* Network Selection */}
      <div style={{ marginBottom: '20px' }}>
        <label style={{
          display: 'block',
          marginBottom: '8px',
          color: 'var(--text-primary)',
          fontWeight: '500',
          fontSize: '14px'
        }}>
          Select broadband network
        </label>
        <CustomSelect
          name="selectedNetwork"
          value={selectedNetwork}
          onChange={(e) => setSelectedNetwork(e.target.value)}
          options={[
            {
              value: NETWORKS.MTN,
              label: (
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                  <img src="/assets/mtnlogo.png" alt="MTN" style={{ width: 24, height: 24, objectFit: 'contain' }} />
                  <span>MTN</span>
                </div>
              )
            },
            {
              value: NETWORKS.TELECEL,
              label: (
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                  <img src="/assets/telecellogo.png" alt="Telecel" style={{ width: 24, height: 24, objectFit: 'contain' }} />
                  <span>Telecel</span>
                </div>
              )
            }
          ]}
          placeholder="Choose network"
          style={{ 
            backgroundColor: 'var(--card)', 
            borderRadius: 'var(--radius-md)',
            border: '1px solid var(--border-secondary)'
          }}
          className="w-full"
        />
      </div>

      {/* MTN Broadband Flow */}
      {selectedNetwork === NETWORKS.MTN && (
        <>
          {/* Destination (landline) */}
          <div style={{ marginBottom: '20px' }}>
            <label style={{
              display: 'block',
              marginBottom: '8px',
              color: 'var(--text-primary)',
              fontWeight: '500',
              fontSize: '14px'
            }}>
              Destination (landline number)
            </label>
            <input
              type="text"
              value={broadbandDestination}
              onChange={(e) => setBroadbandDestination(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && broadbandDestination && isValidGhanaLandline(broadbandDestination)) {
                  e.preventDefault();
                  handleVerify();
                }
              }}
              placeholder="e.g. 0244123456"
              className="input-large w-full"
            />
            {!isVerified && broadbandDestination && isValidGhanaLandline(broadbandDestination) && !isVerifying && (
              <div style={{ marginTop: '8px', textAlign: 'right' }}>
                <button
                  className="btn secondary"
                  onClick={handleVerify}
                  disabled={!broadbandDestination}
                >
                  Check bundles
                </button>
              </div>
            )}
          </div>

          {/* Verification Status */}
          {isVerifying && (
            <div style={{ marginBottom: '12px' }}>
              <p className="utility-hint-text">Verifying broadband destination and fetching bundles...</p>
            </div>
          )}

          {/* Bundle Selection */}
          {isVerified && mtnBroadbandBundles.length > 0 && (
            <div style={{ marginBottom: '20px' }}>
              <label style={{
                display: 'block',
                marginBottom: '8px',
                color: 'var(--text-primary)',
                fontWeight: '500',
                fontSize: '14px'
              }}>
                Select broadband bundle
              </label>
              <select
                value={mtnBroadbandBundles.find((b) => b.name === bundleValue)?.code || ''}
                onChange={handleBundleChange}
                className="input-large w-full"
              >
                <option value="">Choose bundle</option>
                {mtnBroadbandBundles.map((b) => (
                  <option key={b.code} value={b.code}>
                    {b.name} {b.price ? `(GH₵${b.price})` : ''}
                  </option>
                ))}
              </select>
            </div>
          )}

          {/* Amount (read-only when bundle selected) */}
          {isVerified && bundleValue && (
            <div style={{ marginBottom: '20px' }}>
              <label style={{
                display: 'block',
                marginBottom: '8px',
                color: 'var(--text-primary)',
                fontWeight: '500',
                fontSize: '14px'
              }}>
                {t('amount', { ns: 'utilities' })} (GH₵)
              </label>
              <input
                type="number"
                value={amount}
                readOnly
                min="1"
                step="0.01"
                className="input-large w-full"
              />
            </div>
          )}
        </>
      )}

      {/* Telecel Broadband Flow */}
      {selectedNetwork === NETWORKS.TELECEL && (
        <>
          {/* Landline */}
          <div style={{ marginBottom: '20px' }}>
            <label style={{
              display: 'block',
              marginBottom: '8px',
              color: 'var(--text-primary)',
              fontWeight: '500',
              fontSize: '14px'
            }}>
              Landline (Press Enter after typing the Landline)
            </label>
            <input
              type="text"
              value={accountNumber}
              onChange={(e) => setAccountNumber(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && accountNumber && isValidGhanaLandline(accountNumber)) {
                  e.preventDefault();
                  handleVerify();
                }
              }}
              placeholder="e.g. 0244123456"
              className="input-large w-full"
            />
            {!isVerified && accountNumber && isValidGhanaLandline(accountNumber) && !isVerifying && (
              <div style={{ marginTop: '8px', textAlign: 'right' }}>
                <button
                  className="btn secondary"
                  onClick={handleVerify}
                  disabled={!accountNumber}
                >
                  Verify
                </button>
              </div>
            )}
          </div>

          {/* Verification Status */}
          {isVerifying && (
            <div style={{ marginBottom: '12px' }}>
              <p className="utility-hint-text">Verifying broadband account details...</p>
            </div>
          )}

          {/* Verified Fields */}
          {isVerified && (
            <>
              <div style={{ marginBottom: '20px' }}>
                <label style={{
                  display: 'block',
                  marginBottom: '8px',
                  color: 'var(--text-primary)',
                  fontWeight: '500',
                  fontSize: '14px'
                }}>
                  Bundle value (e.g., 1GB)
                </label>
                <input
                  type="text"
                  value={bundleValue}
                  onChange={(e) => setBundleValue(e.target.value)}
                  placeholder="Enter bundle value"
                  className="input-large w-full"
                />
              </div>

              {/* Amount (auto-filled, editable) */}
              <div style={{ marginBottom: '20px' }}>
                <label style={{
                  display: 'block',
                  marginBottom: '8px',
                  color: 'var(--text-primary)',
                  fontWeight: '500',
                  fontSize: '14px'
                }}>
                  {t('amount', { ns: 'utilities' })} (GH₵)
                </label>
                <input
                  type="number"
                  value={amount}
                  onChange={(e) => setAmount(e.target.value)}
                  placeholder={t('enterAmount', { ns: 'utilities' })}
                  min="1"
                  step="0.01"
                  className="input-large w-full"
                />
              </div>

              {/* Customer Details */}
              <CustomerDetailsDisplay
                customerDetails={customerDetails}
                utilityType={UTILITY_PROVIDERS.BROADBAND}
              />
            </>
          )}
        </>
      )}

      {/* Payment Button */}
      {isVerified && (
        <div style={{ textAlign: 'center', marginTop: '24px' }}>
          <button
            className="btn primary w-full"
            onClick={handlePayment}
            disabled={
              payBroadbandMutation.isPending ||
              (selectedNetwork === NETWORKS.MTN && (!bundleValue || !amount)) ||
              (selectedNetwork === NETWORKS.TELECEL && (!accountNumber || !bundleValue || !amount))
            }
            style={{
              padding: '14px 24px',
              fontSize: '16px',
              fontWeight: '600',
            }}
          >
            {payBroadbandMutation.isPending
              ? t('processing', { ns: 'utilities' })
              : `${t('pay', { ns: 'utilities' })} GH₵${amount || '0'}`
            }
          </button>
        </div>
      )}
    </div>
  );
};

export default BroadbandForm;

